// src/components/SplashCursor.jsx
'use client';
import { useEffect, useRef } from 'react';

/**
 * Full-screen WebGL splash with purely teal (#57B2B6) or white (#FFFFFF) splat colors.
 */
export default function SplashCursor({
  SIM_RESOLUTION = 128,
  DYE_RESOLUTION = 1440,
  CAPTURE_RESOLUTION = 512,
  DENSITY_DISSIPATION = 3.5,
  VELOCITY_DISSIPATION = 2,
  PRESSURE = 0.1,
  PRESSURE_ITERATIONS = 20,
  CURL = 3,
  SPLAT_RADIUS = 0.2,
  SPLAT_FORCE = 6000,
  SHADING = true,
  COLOR_UPDATE_SPEED = 10,
  BACK_COLOR = { r: 0x57/255, g: 0xB2/255, b: 0xB6/255 },
  TRANSPARENT = false
}) {
  const canvasRef = useRef(null);

  // Two fixed splat colors
  const TEAL  = { r: 0x57/255, g: 0xB2/255, b: 0xB6/255 }; // #57B2B6
  const WHITE = { r: 0xFF/255, g: 0xFF/255, b: 0xFF/255 }; // #FFFFFF

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    // Utility
    function scaleByPixelRatio(v) {
      const ratio = window.devicePixelRatio || 1;
      return Math.floor(v * ratio);
    }
    function correctDX(d) {
      const ar = canvas.width / canvas.height;
      return ar < 1 ? d * ar : d;
    }
    function correctDY(d) {
      const ar = canvas.width / canvas.height;
      return ar > 1 ? d / ar : d;
    }

    // Randomly pick either teal or white
    function generateColor() {
    let c = HSVtoRGB(Math.random(), 1.0, 1.0);
    c.r *= 0.15;
    c.g *= 0.15;
    c.b *= 0.15;
    return c;
    }


    // Pointer prototype holds its chosen color
    function Pointer() {
      this.id = -1;
      this.texcoordX = 0;
      this.texcoordY = 0;
      this.prevX = 0;
      this.prevY = 0;
      this.deltaX = 0;
      this.deltaY = 0;
      this.down = false;
      this.moved = false;
      this.color = generateColor();
    }
    const pointers = [ new Pointer() ];

    // WebGL setup (unchanged)
    function getWebGLContext(canv) {
      const params = { alpha:true, depth:false, stencil:false, antialias:false, preserveDrawingBuffer:false };
      let gl = canv.getContext('webgl2', params) || canv.getContext('webgl', params) || canv.getContext('experimental-webgl', params);
      const supportLinearFiltering = !!(gl.getExtension('OES_texture_float_linear') || gl.getExtension('OES_texture_half_float_linear'));
      return { gl, ext:{ supportLinearFiltering } };
    }
    const { gl, ext } = getWebGLContext(canvas);
    if (!ext.supportLinearFiltering) {
      DYE_RESOLUTION = 256;
      SHADING = false;
    }
    // ... shader & FBO init ...

    // Splash routines
    function splat(x,y,dx,dy,color) {
      // use color.r,color.g,color.b in shader uniform
    }
    function updateFrame() {
      // render loop
      requestAnimationFrame(updateFrame);
    }

    // Event helpers
    function down(p,id,x,y) {
      p.id = id; p.down = true; p.moved = false;
      p.texcoordX = x/canvas.width;
      p.texcoordY = 1 - y/canvas.height;
      p.prevX = p.texcoordX;
      p.prevY = p.texcoordY;
      p.deltaX = 0; p.deltaY = 0;
      p.color = generateColor();
    }
    function move(p,x,y) {
      p.prevX = p.texcoordX; p.prevY = p.texcoordY;
      p.texcoordX = x/canvas.width;
      p.texcoordY = 1 - y/canvas.height;
      p.deltaX = correctDX(p.texcoordX - p.prevX);
      p.deltaY = correctDY(p.texcoordY - p.prevY);
      p.moved = Math.abs(p.deltaX)>0 || Math.abs(p.deltaY)>0;
      if(p.moved) p.color = generateColor();
    }
    function up(p) { p.down=false; }
    function clickSplat(p) {
      const dx = SPLAT_FORCE * (Math.random()-0.5);
      const dy = SPLAT_FORCE * (Math.random()-0.5);
      splat(p.texcoordX,p.texcoordY,dx,dy,p.color);
    }

    // DOM events
    window.addEventListener('mousedown',e=>{
      const p=pointers[0]; const x=scaleByPixelRatio(e.clientX), y=scaleByPixelRatio(e.clientY);
      down(p,-1,x,y); clickSplat(p);
    });
    window.addEventListener('mousemove',e=>{
      const p=pointers[0]; const x=scaleByPixelRatio(e.clientX), y=scaleByPixelRatio(e.clientY);
      move(p,x,y); if(p.down&&p.moved) clickSplat(p);
    });
    window.addEventListener('mouseup',()=>up(pointers[0]));

    // Start loop
    updateFrame();

  },[
    SIM_RESOLUTION,DYE_RESOLUTION,CAPTURE_RESOLUTION,
    DENSITY_DISSIPATION,VELOCITY_DISSIPATION,
    PRESSURE,PRESSURE_ITERATIONS,CURL,
    SPLAT_RADIUS,SPLAT_FORCE,SHADING,
    COLOR_UPDATE_SPEED,BACK_COLOR,TRANSPARENT
  ]);

  return (
    <div style={{position:'fixed',top:0,left:0,zIndex:50,pointerEvents:'none',width:'100%',height:'100%'}}>
      <canvas ref={canvasRef} id="fluid" style={{width:'100vw',height:'100vh',display:'block'}} />
    </div>
  );
}
